#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* newNode(int val) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->left = node->right = NULL;
    return node;
}

// Function to print leaf nodes
void printLeaves(Node* root) {
    if (root == NULL)
        return;

    printLeaves(root->left);

    if (root->left == NULL && root->right == NULL)
        printf("%d ", root->val);

    printLeaves(root->right);
}

// Function to print the left boundary nodes
void printBoundaryLeft(Node* root) {
    if (root == NULL || (root->left == NULL && root->right == NULL))
        return;

    printf("%d ", root->val);

    if (root->left)
        printBoundaryLeft(root->left);
    else
        printBoundaryLeft(root->right);
}

// Function to print the right boundary nodes
void printBoundaryRight(Node* root) {
    if (root == NULL || (root->left == NULL && root->right == NULL))
        return;

    if (root->right)
        printBoundaryRight(root->right);
    else
        printBoundaryRight(root->left);

    printf("%d ", root->val);
}

// Function to print the boundary of the binary tree
void printBoundary(Node* root) {
    if (root == NULL)
        return;

    printf("%d ", root->val);

    printBoundaryLeft(root->left);

    printLeaves(root->left);
    printLeaves(root->right);

    printBoundaryRight(root->right);
}

int main() {
    int N;
    scanf("%d", &N);

    Node* nodes[N];
    for (int i = 0; i < N; i++)
        nodes[i] = newNode(i + 1);

    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);

        if (Ri == 'L')
            nodes[pi - 1]->left = nodes[ci - 1];
        else
            nodes[pi - 1]->right = nodes[ci - 1];
    }

    printBoundary(nodes[0]);

    return 0;
}

