    static void printLeaves(Node root) {
        if (root == null)
            return;

        printLeaves(root.left);

        if (root.left == null && root.right == null)
            System.out.print(root.val + " ");

        printLeaves(root.right);
    }

    // Function to print the left boundary nodes
    static void printBoundaryLeft(Node root) {
        if (root == null || (root.left == null && root.right == null))
            return;

        System.out.print(root.val + " ");

        if (root.left != null)
            printBoundaryLeft(root.left);
        else
            printBoundaryLeft(root.right);
    }

    // Function to print the right boundary nodes
    static void printBoundaryRight(Node root) {
        if (root == null || (root.left == null && root.right == null))
            return;

        if (root.right != null)
            printBoundaryRight(root.right);
        else
            printBoundaryRight(root.left);

        System.out.print(root.val + " ");
    }

    // Function to print the boundary of the binary tree
    static void printBoundary(Node root) {
        if (root == null)
            return;

        System.out.print(root.val + " ");

        printBoundaryLeft(root.left);

        printLeaves(root.left);
        printLeaves(root.right);

        printBoundaryRight(root.right);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();

        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++)
            nodes[i] = new Node(i + 1);

        for (int i = 0; i < N - 1; i++) {
            int pi = sc.nextInt(), ci = sc.nextInt();
            char Ri = sc.next().charAt(0);

            if (Ri == 'L')
                nodes[pi - 1].left = nodes[ci - 1];
            else
                nodes[pi - 1].right = nodes[ci - 1];
        }

        printBoundary(nodes[0]);
    }
}

